VALUES
  ('disabled-23e15ae5-moex-00110', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '利用人性弱點，以簡單的溝通和欺騙技倆，獲取帳號、密碼、身分證號碼 或其他機敏資料，用以穿透資通安全防護，達到非法資料存取與系統破壞 的行為，稱為：', '["人因工程", "社群工程", "駭客工程", "社交工程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "0389d105f1be", "answer_pdf_sha1": "9919953e41f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00111', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列「」中成語使用正確的是：', '["那位講者善於帶動氣氛，總能使聽眾的情緒「水漲船高」", "這場會議開放現場直播，「嘩眾取寵」以增加民眾參與度", "他家遭到小偷「一窺堂奧」，貴重物品及錢財全都不翼而飛", "公務員做事應「行不由徑」，禁得起時間及社會大眾的檢驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00112', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列「」中成語使用正確的是：', '["小五年紀小，心胸寬大，辦事沉穩，不愧為「班門弄斧」之材", "老范歷練豐富，見多識廣，誠可謂是「坐井觀天」，人所難及", "逢迎拍馬也許是條升遷的「終南捷徑」，但賢人君子不屑為之", "小蕙雖才就讀小學一年級，但已能「望文生義」，認得許多字"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00113', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列文句「」中與虎相關的詞語，何者運用正確？', '["為落實環保永續精神，「與虎謀皮」的潮流已不再", "有了「為虎作倀」的得力助手，今年業務拓展順利", "這個孩子體格雄健好丰姿，不愧是「將門出虎子」", "此處山嵐繚繞，鳥語花香，可謂「龍潭虎穴」寶地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00114', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列「」中詞語的使用，何者正確？', '["事件的經過眾說紛紜，已經成為一場「羅生門」，很難釐清發展的脈絡", "長官必須以身作則，親自「捉刀」，才能樹立嚴謹風氣，強化組織效能", "每個人都應當學習控制情緒，「擲地有聲」的反應，事後往往追悔莫及", "酒後不開車已是全民共識，有「亡羊補牢」的意識，才能確保行車安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00115', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「自視過高的人，往往不知檢討自己的不足。山外青山樓外 樓， ，任何人都不會永遠處於絕對優勢。無論你地位多高， 權勢多大，都應學會『低人一等』，不要用自己的優勢去碾壓別人，逞一 時之強。」 文中 內最適合填入的句子是：', '["莫待無時思有時", "強中自有強中手", "不是冤家不聚頭", "天下名山僧占多"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00116', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列「」中詞語的使用，何者正確？', '["應當仔細聆聽法官「庭訓」，知錯能改，才能洗心革面", "幸虧有人製造笑料，「從中作梗」，才能緩解尷尬的氣氛", "獨學而無友，透過相互切磋，「同室操戈」，才能一同精進", "許多傳統技藝，因工作辛勞，面臨無人傳承「衣缽」的窘境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00117', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列語句，何者無冗贅之語病？', '["為數眾多的莘莘學子正寒窗苦讀", "這款遊戲竄紅後，氣勢難以抵擋", "初次來到您的貴寶地，請多海涵", "天天五蔬果，有助裨益身心健康"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00118', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '〇〇高中秘書室代表學校寄畢業典禮邀請函給市長，信封的正確寫法是：', '["〇〇〇市長 安啟", "〇市長〇〇 台啟", "〇〇〇市長 大啟", "〇市長〇〇 鈞啟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00119', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列題辭適用於祝人升遷的是：', '["堂構增輝", "秀茁蘭枝", "青雲直上", "群賢畢至"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
